update_existing_workflow.update_script_template:
const fs = require('fs');
const sqlite3 = require('/usr/local/lib/node_modules/n8n/node_modules/.pnpm/sqlite3@5.1.7/node_modules/sqlite3');
const db = new sqlite3.Database('/home/node/.n8n/database.sqlite');
const wf = JSON.parse(fs.readFileSync('/tmp/workflow.json', 'utf8'));
db.run(
  'UPDATE workflow_entity SET nodes = ?, connections = ?, updatedAt = datetime("now") WHERE id = ?',
  [JSON.stringify(wf.nodes), JSON.stringify(wf.connections), 'WORKFLOW_ID_HERE'],
  function(err) { console.log(err || 'Updated: ' + this.changes); db.close(); }
);
